`timescale 1ns/1ps

module tb_wallace_reduction();

    // 1. Signal declarations
    reg [7:0] p0, p1, p2;
    wire [7:0] sum, carry;

    // 2. DUT instantiation
    wallace_reduction dut (
        .p0(p0),
        .p1(p1),
        .p2(p2),
        .sum(sum),
        .carry(carry)
    );

    // 3. Clock generation (if needed)
    reg clk = 0;
    always #5 clk = ~clk;

    // 4. Waveform dump
    initial begin
        $dumpfile("dump.vcd");
        $dumpvars(0, tb_wallace_reduction);
    end
